      "type": "code",
      "language": "ts",
      "label": "src/learning/react/chapter-16-sellerhub-capstone/sellerhub-capstone-app/shared/observability/error-reporter.ts",
      "value": "import type { SellerHubError } from '../errors/normalize-sellerhub-error'\n\nexport type SellerHubErrorEvent = {\n  code: string\n  feature: string\n  kind: SellerHubError['kind']\n  occurredAt: string\n  privacy: 'no-sensitive-payload'\n  release: string\n  route: string\n}\n\nexport type SellerHubErrorContext = {\n  feature: string\n  privacy: SellerHubErrorEvent['privacy']\n  release: string\n  route: string\n}\n\nexport type SellerHubErrorReporter = {\n  report: (\n    context: SellerHubErrorContext,\n    error: SellerHubError,\n  ) => SellerHubErrorEvent\n  read: () => readonly SellerHubErrorEvent[]\n}\n\nexport function createSellerHubErrorReporter(): SellerHubErrorReporter {\n  const events: SellerHubErrorEvent[] = []\n\n  return {\n    report(context, error) {\n      const event = {\n        code: error.code,\n        feature: context.feature,\n        kind: error.kind,\n        occurredAt: new Date('2026-06-28T09:00:00.000Z').toISOString(),\n        privacy: context.privacy,\n        release: context.release,\n        route: context.route,\n      }\n      events.push(event)\n      return event\n    },\n    read() {\n      return events\n    },\n  }\n}"
